export function getIcon (name, w = 0, h = 0) {
  let i = icons.find(icon => icon.name.toLowerCase().trim() === name.toLowerCase().trim())?.icon
  if (i && w > 0) {
    i = i.replace(/width="[^"]*"/, `width="${w}"`)
  }
  if (i && h > 0) {
    i = i.replace(/height="[^"]*"/, `height="${h}"`)
  }
  return i
}
